evaluators.evaluation_logic:
const checkpoints = [];

const retreats = JSON.parse(localStorage.getItem('retreats') || '[]');
const sessions = JSON.parse(localStorage.getItem('retreat_sessions') || '[]');
const allBookings = JSON.parse(localStorage.getItem('retreat_bookings') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

// Baseline date to distinguish preloaded data from user actions
let baselineDateStr = metadata && metadata.baselineDate ? metadata.baselineDate : '2026-03-03';
const baseline = new Date(baselineDateStr + 'T00:00:00Z');

// Only consider bookings created on/after baseline
const bookings = allBookings.filter(b => {
  if (!b.created_at) return true;
  const created = new Date(b.created_at);
  return created >= baseline;
});

// Compute next month relative to baseline
const baseDate = baseline;
let nextMonthYear = baseDate.getUTCFullYear();
let nextMonthIndex = baseDate.getUTCMonth() + 1; // 0-11
if (nextMonthIndex > 11) {
  nextMonthIndex = 0;
  nextMonthYear += 1;
}

function isInNextMonth(iso) {
  if (!iso) return false;
  const d = new Date(iso);
  return d.getUTCFullYear() === nextMonthYear && d.getUTCMonth() === nextMonthIndex;
}

const meditationRetreatIds = retreats.filter(r => r.type === 'meditation').map(r => r.id);

// All retreat sessions that match the task criteria (type, duration, month, options)
const qualifyingSessions = sessions.filter(rs => {
  if (!meditationRetreatIds.includes(rs.retreat_id)) return false;
  if (typeof rs.duration_days !== 'number' || rs.duration_days !== 3) return false;
  if (!isInNextMonth(rs.start_date)) return false;
  const hasPrivateRoom = Array.isArray(rs.available_room_types) && rs.available_room_types.some(rt => rt === 'standard_private_room' || rt === 'deluxe_private_suite');
  if (!hasPrivateRoom) return false;
  const hasVeg = Array.isArray(rs.available_meal_plans) && rs.available_meal_plans.includes('vegetarian');
  if (!hasVeg) return false;
  return true;
});

// Determine the cheapest of these sessions by base_price
let cheapestPrice = null;
qualifyingSessions.forEach(rs => {
  if (typeof rs.base_price === 'number') {
    if (cheapestPrice === null || rs.base_price < cheapestPrice) {
      cheapestPrice = rs.base_price;
    }
  }
});
const cheapestSessionIds = qualifyingSessions.filter(rs => rs.base_price === cheapestPrice).map(rs => rs.id);

const privateRoomTypes = ['standard_private_room', 'deluxe_private_suite'];

// Bookings that match all criteria except "cheapest" constraint
const qualifyingBookings = bookings.filter(b => {
  const rs = sessions.find(s => s.id === b.retreat_session_id);
  if (!rs) return false;
  if (!meditationRetreatIds.includes(rs.retreat_id)) return false;
  if (rs.duration_days !== 3) return false;
  if (!isInNextMonth(rs.start_date)) return false;
  if (!privateRoomTypes.includes(b.room_type)) return false;
  if (b.meal_plan !== 'vegetarian') return false;
  const roomOk = !Array.isArray(rs.available_room_types) || rs.available_room_types.includes(b.room_type);
  const mealOk = !Array.isArray(rs.available_meal_plans) || rs.available_meal_plans.includes(b.meal_plan);
  return roomOk && mealOk;
});

// CP1 (0.4): User created at least one booking matching all retreat criteria (type, 3 days, next month, private room, vegetarian meals)
checkpoints.push({ passed: qualifyingBookings.length > 0, weight: 0.4 });

// CP2 (0.6): At least one such booking is for the CHEAPEST qualifying session
const hasCheapestBooking = qualifyingBookings.some(b => cheapestSessionIds.includes(b.retreat_session_id));
checkpoints.push({ passed: cheapestSessionIds.length > 0 && hasCheapestBooking, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const courses = JSON.parse(localStorage.getItem('courses') || '[]');
const tiers = JSON.parse(localStorage.getItem('course_tiers') || '[]');
const allEnrollments = JSON.parse(localStorage.getItem('course_enrollments') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

let baselineDateStr = metadata && metadata.baselineDate ? metadata.baselineDate : '2026-03-03';
const baseline = new Date(baselineDateStr + 'T00:00:00Z');
const windowEnd = new Date(baseline.getTime() + 14 * 24 * 60 * 60 * 1000);

function isWithin14Days(iso) {
  if (!iso) return false;
  const d = new Date(iso);
  return d >= baseline && d <= windowEnd;
}

// Candidate courses that match the task constraints
const candidateCourses = courses.filter(c => {
  if (c.level !== 'beginner') return false;
  if (!isWithin14Days(c.start_date)) return false;
  if (typeof c.base_price !== 'number' || c.base_price >= 300) return false;
  if (!c.has_live_qa) return false;
  return true;
});

let topRating = null;
candidateCourses.forEach(c => {
  if (typeof c.rating === 'number') {
    if (topRating === null || c.rating > topRating) topRating = c.rating;
  }
});
const topRatedCourseIds = candidateCourses.filter(c => c.rating === topRating).map(c => c.id);

// Helper: for a course, find the lowest-priced non-premium tier price
function getNonPremiumMinPrice(courseId) {
  const courseTiers = tiers.filter(t => t.course_id === courseId && t.is_active !== false);
  const nonPremium = courseTiers.filter(t => t.tier_type !== 'premium');
  if (nonPremium.length === 0) return null;
  let minPrice = null;
  nonPremium.forEach(t => {
    if (typeof t.price === 'number') {
      if (minPrice === null || t.price < minPrice) minPrice = t.price;
    }
  });
  return minPrice;
}

// Only consider enrollments created after baseline
const enrollments = allEnrollments.filter(e => {
  if (!e.created_at) return true;
  const created = new Date(e.created_at);
  return created >= baseline;
});

// Enrollments that meet all course-level criteria and tier rule (standard or lowest non-premium)
const qualifyingEnrollments = enrollments.filter(e => {
  const course = courses.find(c => c.id === e.course_id);
  const tier = tiers.find(t => t.id === e.course_tier_id);
  if (!course || !tier) return false;

  // Course-level constraints
  if (course.level !== 'beginner') return false;
  if (!isWithin14Days(course.start_date)) return false;
  if (typeof course.base_price !== 'number' || course.base_price >= 300) return false;
  if (!course.has_live_qa) return false;

  // Tier constraints
  const nonPremMinPrice = getNonPremiumMinPrice(course.id);
  if (nonPremMinPrice == null) return false;
  const isStandard = tier.tier_type === 'standard';
  const isLowestNonPremium = (tier.tier_type !== 'premium') && (tier.price === nonPremMinPrice);
  if (!isStandard && !isLowestNonPremium) return false;

  return true;
});

// CP1 (0.4): Enrolled in some course that meets all constraints and uses an allowed tier
checkpoints.push({ passed: qualifyingEnrollments.length > 0, weight: 0.4 });

// CP2 (0.6): At least one such enrollment is for the HIGHEST-RATED qualifying course
const hasTopRatedEnrollment = qualifyingEnrollments.some(e => topRatedCourseIds.includes(e.course_id));
checkpoints.push({ passed: topRatedCourseIds.length > 0 && hasTopRatedEnrollment, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const mentors = JSON.parse(localStorage.getItem('mentors') || '[]');
const services = JSON.parse(localStorage.getItem('mentor_services') || '[]');
const slots = JSON.parse(localStorage.getItem('mentor_availability_slots') || '[]');
const allAppts = JSON.parse(localStorage.getItem('mentoring_appointments') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

let baselineDateStr = metadata && metadata.baselineDate ? metadata.baselineDate : '2026-03-03';
const baseline = new Date(baselineDateStr + 'T00:00:00Z');

// Reconstruct the "first two mentors shown" using the searchMentors logic with filters (60-min, <=120, one_on_one_session)
const eligiblePairs = [];
mentors.filter(m => m.is_active !== false).forEach(m => {
  let svc = services.filter(s => s.mentor_id === m.id && s.is_active !== false && s.service_type === 'one_on_one_session');
  svc = svc.filter(s => s.duration_minutes === 60 && typeof s.price === 'number' && s.price <= 120);
  if (svc.length === 0) return;
  svc.sort((a, b) => (a.price || 0) - (b.price || 0));
  eligiblePairs.push({ mentor: m, service: svc[0] });
});

eligiblePairs.sort((a, b) => (b.mentor.years_experience || 0) - (a.mentor.years_experience || 0));
const firstTwo = eligiblePairs.slice(0, 2);
let chosenMentorId = null;
if (firstTwo.length === 1) {
  chosenMentorId = firstTwo[0].mentor.id;
} else if (firstTwo.length === 2) {
  const m1 = firstTwo[0].mentor;
  const m2 = firstTwo[1].mentor;
  chosenMentorId = (m1.years_experience || 0) >= (m2.years_experience || 0) ? m1.id : m2.id;
}

// All qualifying services for the chosen mentor
const chosenServices = services.filter(s => s.mentor_id === chosenMentorId && s.service_type === 'one_on_one_session' && s.duration_minutes === 60 && typeof s.price === 'number' && s.price <= 120 && s.is_active !== false);
const chosenServiceIds = chosenServices.map(s => s.id);

function getNextFriday(base) {
  const d = new Date(Date.UTC(base.getUTCFullYear(), base.getUTCMonth(), base.getUTCDate()));
  const day = d.getUTCDay();
  let offset = 5 - day; // Friday = 5
  if (offset <= 0) offset += 7; // ensure "next" Friday, not same-day
  d.setUTCDate(d.getUTCDate() + offset);
  return d;
}

const nextFriday = getNextFriday(baseline);

function isOnNextFridayInWindow(iso) {
  if (!iso) return false;
  const d = new Date(iso);
  if (d.getUTCFullYear() !== nextFriday.getUTCFullYear()) return false;
  if (d.getUTCMonth() !== nextFriday.getUTCMonth()) return false;
  if (d.getUTCDate() !== nextFriday.getUTCDate()) return false;
  const h = d.getUTCHours();
  // Start time between 16:00 and before 19:00
  return h >= 16 && h < 19;
}

// Only consider appointments created after baseline
const appts = allAppts.filter(a => {
  if (!a.created_at) return true;
  const created = new Date(a.created_at);
  return created >= baseline;
});

// Appointments that meet time/length/price constraints, regardless of mentor
const windowAppts = appts.filter(a => {
  if (!isOnNextFridayInWindow(a.start_datetime)) return false;
  const svc = services.find(s => s.id === a.mentor_service_id);
  if (!svc) return false;
  if (svc.service_type !== 'one_on_one_session') return false;
  if (svc.duration_minutes !== 60) return false;
  if (typeof svc.price !== 'number' || svc.price > 120) return false;
  return true;
});

// CP1 (0.4): User booked at least one 60-min 1:1 session under $120 on next Friday between 4–7pm (any mentor)
checkpoints.push({ passed: windowAppts.length > 0, weight: 0.4 });

// CP2 (0.6): At least one such appointment is with the more experienced of the first two eligible mentors
const hasChosenMentorAppt = windowAppts.some(a => a.mentor_id === chosenMentorId && chosenServiceIds.includes(a.mentor_service_id));
checkpoints.push({ passed: !!chosenMentorId && hasChosenMentorAppt, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const packages = JSON.parse(localStorage.getItem('custom_retreat_packages') || '[]');
const workshops = JSON.parse(localStorage.getItem('workshops') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

let baselineDateStr = metadata && metadata.baselineDate ? metadata.baselineDate : '2026-03-03';
const baseline = new Date(baselineDateStr + 'T00:00:00Z');

// Determine next month (calendar) relative to baseline
let nextMonthYear = baseline.getUTCFullYear();
let nextMonthIndex = baseline.getUTCMonth() + 1;
if (nextMonthIndex > 11) {
  nextMonthIndex = 0;
  nextMonthYear += 1;
}

function isStartInNextMonth(iso) {
  if (!iso) return false;
  const d = new Date(iso);
  return d.getUTCFullYear() === nextMonthYear && d.getUTCMonth() === nextMonthIndex;
}

// Only consider packages created after baseline
const userPkgs = packages.filter(p => {
  if (!p.created_at) return true;
  const created = new Date(p.created_at);
  return created >= baseline;
});

// 5-day, mid-range room (standard_private_room) starting next month
const basePkgs = userPkgs.filter(p => {
  if (p.length_days !== 5) return false;
  if (!isStartInNextMonth(p.start_date)) return false;
  if (p.room_type !== 'standard_private_room') return false;
  return true;
});

// CP1 (0.4): At least one custom retreat package matches 5 days, next month start, mid-range room
checkpoints.push({ passed: basePkgs.length > 0, weight: 0.4 });

// Among those, check workshop conditions
const validWorkshopPkgs = basePkgs.filter(p => {
  const ids = Array.isArray(p.workshop_ids) ? p.workshop_ids : [];
  if (ids.length !== 3) return false;
  const selected = workshops.filter(w => ids.includes(w.id));
  if (selected.length !== 3) return false;
  let allUnder50 = true;
  let hasSoundHealing = false;
  selected.forEach(w => {
    if (typeof w.price !== 'number' || w.price >= 50) allUnder50 = false;
    if (w.is_sound_healing) hasSoundHealing = true;
  });
  if (!allUnder50) return false;
  if (!hasSoundHealing) return false;
  return true;
});

// CP2 (0.6): At least one such package also has exactly 3 workshops all < $50 with ≥1 sound healing
checkpoints.push({ passed: validWorkshopPkgs.length > 0, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const products = JSON.parse(localStorage.getItem('products') || '[]');

const activeCart = carts.find(c => c.status === 'active');
let items = [];
if (activeCart) {
  items = cartItems.filter(ci => ci.cart_id === activeCart.id);
}

function getProduct(ci) {
  return products.find(p => p.id === ci.product_id) || null;
}

// Identify qualifying items by category and constraints
let qualifyingCushions = [];
let qualifyingJournals = [];
let qualifyingIncense = [];

items.forEach(ci => {
  const p = getProduct(ci);
  if (!p) return;
  if (p.category === 'meditation_gear' && typeof p.price === 'number' && p.price < 60) {
    qualifyingCushions.push({ ci, p });
  }
  if (p.category === 'journals' && typeof p.price === 'number' && p.price < 25) {
    qualifyingJournals.push({ ci, p });
  }
  if (p.category === 'incense_scents' && typeof p.rating === 'number' && p.rating >= 4.0) {
    qualifyingIncense.push({ ci, p });
  }
});

// CP1 (0.4): Cart has at least one qualifying cushion, one qualifying journal, and one qualifying incense (any extra items allowed)
const cp1Passed = !!activeCart && qualifyingCushions.length >= 1 && qualifyingJournals.length >= 1 && qualifyingIncense.length >= 1;
checkpoints.push({ passed: cp1Passed, weight: 0.4 });

// CP2 (0.6): Cart has EXACTLY three line items, each quantity 1, consisting of exactly one qualifying cushion, one qualifying journal, and one qualifying incense, with no other items
let cp2Passed = false;
if (activeCart && items.length === 3) {
  let cushionCount = 0;
  let journalCount = 0;
  let incenseCount = 0;
  let invalidLine = false;

  items.forEach(ci => {
    if (invalidLine) return;
    const p = getProduct(ci);
    if (!p) { invalidLine = true; return; }
    if (ci.quantity !== 1) { invalidLine = true; return; }

    if (p.category === 'meditation_gear' && typeof p.price === 'number' && p.price < 60) {
      cushionCount++;
    } else if (p.category === 'journals' && typeof p.price === 'number' && p.price < 25) {
      journalCount++;
    } else if (p.category === 'incense_scents' && typeof p.rating === 'number' && p.rating >= 4.0) {
      incenseCount++;
    } else {
      invalidLine = true;
    }
  });

  if (!invalidLine && cushionCount === 1 && journalCount === 1 && incenseCount === 1) {
    cp2Passed = true;
  }
}
checkpoints.push({ passed: cp2Passed, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const events = JSON.parse(localStorage.getItem('events') || '[]');
const allRegs = JSON.parse(localStorage.getItem('event_registrations') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

let baselineDateStr = metadata && metadata.baselineDate ? metadata.baselineDate : '2026-03-03';
const baseline = new Date(baselineDateStr + 'T00:00:00Z');
const baseYear = baseline.getUTCFullYear();
const baseMonth = baseline.getUTCMonth();

function isCurrentMonth(iso) {
  if (!iso) return false;
  const d = new Date(iso);
  return d.getUTCFullYear() === baseYear && d.getUTCMonth() === baseMonth;
}

function isWeekday(d) {
  const dow = d.getUTCDay();
  return dow >= 1 && dow <= 5;
}

// Only consider registrations created after baseline
const regs = allRegs.filter(r => {
  if (!r.created_at) return true;
  const created = new Date(r.created_at);
  return created >= baseline;
});

function matchStep1(e, r) {
  if (!e) return false;
  if (r.attendees_count !== 1) return false;
  if (!isCurrentMonth(e.start_datetime)) return false;
  if (!['community', 'community_circle'].includes(e.event_type)) return false;
  if (e.price_type !== 'free') return false;
  return true;
}

function matchStep2(e, r) {
  if (!matchStep1(e, r)) return false;
  const d = new Date(e.start_datetime);
  return isWeekday(d);
}

function matchStep3(e, r) {
  if (!matchStep2(e, r)) return false;
  const d = new Date(e.start_datetime);
  const h = d.getUTCHours();
  if (h < 18) return false; // evening start
  if (typeof e.spots_remaining !== 'number' || e.spots_remaining <= 20) return false;
  return true;
}

let step1 = false, step2 = false, step3 = false;
regs.forEach(r => {
  const e = events.find(ev => ev.id === r.event_id);
  if (matchStep1(e, r)) step1 = true;
  if (matchStep2(e, r)) step2 = true;
  if (matchStep3(e, r)) step3 = true;
});

// CP1 (0.3): Registration to a free community/community_circle event this month for exactly 1 attendee (time/day not yet checked)
checkpoints.push({ passed: step1, weight: 0.3 });

// CP2 (0.3): Such registration is on a weekday
checkpoints.push({ passed: step2, weight: 0.3 });

// CP3 (0.4): Such registration is on a weekday evening (start ≥ 18:00) and event has >20 spots remaining
checkpoints.push({ passed: step3, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const playlists = JSON.parse(localStorage.getItem('playlists') || '[]');
const playlistItems = JSON.parse(localStorage.getItem('playlist_items') || '[]');
const libraryItems = JSON.parse(localStorage.getItem('library_items') || '[]');

const targetPlaylist = playlists.find(p => (p.name || '').trim().toLowerCase() === 'bedtime practice');
let plItems = [];
if (targetPlaylist) {
  plItems = playlistItems.filter(pi => pi.playlist_id === targetPlaylist.id);
}

function isSleepOrRestItem(li) {
  if (!li) return false;
  const cat = (li.primary_category || '').toLowerCase();
  const tags = Array.isArray(li.tags) ? li.tags.map(t => (t || '').toLowerCase()) : [];
  if (cat === 'sleep' || cat === 'rest') return true;
  if (tags.includes('sleep') || tags.includes('rest')) return true;
  return false;
}

function isQualifyingItem(li) {
  if (!li) return false;
  if (li.content_type !== 'audio') return false;
  if (!li.is_guided) return false;
  if (!isSleepOrRestItem(li)) return false;
  if (typeof li.duration_minutes !== 'number' || li.duration_minutes < 10 || li.duration_minutes > 20) return false;
  if (typeof li.rating !== 'number' || li.rating < 4.5) return false;
  return true;
}

const qualifyingPlItems = plItems.filter(pi => {
  const li = libraryItems.find(it => it.id === pi.library_item_id);
  return isQualifyingItem(li);
});

// CP1 (0.4): There is a 'Bedtime Practice' playlist with at least one qualifying guided sleep/rest audio item
checkpoints.push({ passed: !!targetPlaylist && qualifyingPlItems.length >= 1, weight: 0.4 });

// CP2 (0.6): That playlist has exactly 3 unique items, and all 3 are qualifying
let cp2Passed = false;
if (targetPlaylist && plItems.length === 3) {
  const allQualifying = plItems.every(pi => {
    const li = libraryItems.find(it => it.id === pi.library_item_id);
    return isQualifyingItem(li);
  });
  const uniqueIds = new Set(plItems.map(pi => pi.library_item_id));
  if (allQualifying && uniqueIds.size === 3) {
    cp2Passed = true;
  }
}
checkpoints.push({ passed: cp2Passed, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

// Instrumentation: whether FAQ search for 'wheelchair' was performed
let faqSearchFlag = null;
try {
  faqSearchFlag = JSON.parse(localStorage.getItem('task8_faqWheelchairSearch') || 'null');
} catch (e) {
  faqSearchFlag = null;
}

const messages = JSON.parse(localStorage.getItem('contact_messages') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

let baselineDateStr = metadata && metadata.baselineDate ? metadata.baselineDate : '2026-03-03';
const baseline = new Date(baselineDateStr + 'T00:00:00Z');

// Only consider contact messages created after baseline
const userMessages = messages.filter(m => {
  if (!m.created_at) return true;
  const created = new Date(m.created_at);
  return created >= baseline;
});

function matchesTopicAndMethod(msg) {
  if (!msg) return false;
  if (msg.topic !== 'accessibility_dietary_needs') return false;
  if (msg.preferred_contact_method !== 'phone') return false;
  return true;
}

function containsRequiredPhrases(msg) {
  if (!msg || !msg.message) return false;
  const text = msg.message.toLowerCase();
  const hasWheelchair = text.includes('wheelchair');
  const hasDairyFree = text.includes('dairy-free') || text.includes('dairy free');
  return hasWheelchair && hasDairyFree;
}

const topicAndMethodMsgs = userMessages.filter(matchesTopicAndMethod);
const fullyMatchingMsgs = topicAndMethodMsgs.filter(containsRequiredPhrases);

// CP1 (0.3): Instrumentation shows user searched FAQ with keyword 'wheelchair'
checkpoints.push({ passed: faqSearchFlag === true, weight: 0.3 });

// CP2 (0.3): At least one contact message uses accessibility/dietary topic AND phone as preferred contact method
checkpoints.push({ passed: topicAndMethodMsgs.length > 0, weight: 0.3 });

// CP3 (0.4): At least one such message also explicitly mentions both 'wheelchair' and 'dairy-free' (or 'dairy free')
checkpoints.push({ passed: fullyMatchingMsgs.length > 0, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
